    25→// CreateModel stores a new LLM model
    26→func (s *LLMModelStorage) CreateModel(ctx context.Context, model *models.LLMModel) error {
    27→	key := fmt.Sprintf("llms/models/%s", model.ID)
    28→
    29→	// Check if model already exists
    30→	exists, err := s.storage.Exists(ctx, key)
    31→	if err != nil {
    32→		return fmt.Errorf("failed to check model existence: %w", err)
    33→	}
    34→	if exists {
    35→		return fmt.Errorf("model already exists: %s", model.ID)
    36→	}
    37→
    38→	// Set system fields
    39→	model.SetSystemFields()
    40→
    41→	// Serialize model
    42→	data, err := json.Marshal(model)
    43→	if err != nil {
    44→		return fmt.Errorf("failed to serialize model: %w", err)
    45→	}
    46→
    47→	// Store in storage
    48→	reader := strings.NewReader(string(data))
    49→	if err := s.storage.Put(ctx, key, reader, WithContentType("application/json")); err != nil {
    50→		return fmt.Errorf("failed to store model: %w", err)
    51→	}
    52→
    53→	return nil
    54→}
