   209→// SearchModels searches for models by name or description (simple text search)
   210→func (s *LLMModelStorage) SearchModels(ctx context.Context, query string) ([]*models.LLMModel, error) {
   211→	// List all models first
   212→	filter := ListModelFilter{Limit: 1000} // Large limit for search
   213→	allModels, _, err := s.ListModels(ctx, filter)
   214→	if err != nil {
   215→		return nil, fmt.Errorf("failed to list models for search: %w", err)
   216→	}
   217→
   218→	// Filter by query (simple case-insensitive text search)
   219→	queryLower := strings.ToLower(query)
   220→	results := make([]*models.LLMModel, 0)
   221→
   222→	for _, model := range allModels {
   223→		// Check if query matches ID, name, or provider
   224→		if strings.Contains(strings.ToLower(model.ID), queryLower) ||
   225→			strings.Contains(strings.ToLower(model.Name), queryLower) ||
   226→			strings.Contains(strings.ToLower(model.Provider), queryLower) {
   227→			results = append(results, model)
   228→		}
   229→	}
   230→
   231→	return results, nil
   232→}
