    50→// validateModelID provides additional ID format validation
    51→func (v *LLMModelValidator) validateModelID(id string) error {
    52→	if len(id) < 3 {
    53→		return fmt.Errorf("model ID too short (minimum 3 characters)")
    54→	}
    55→
    56→	if len(id) > 100 {
    57→		return fmt.Errorf("model ID too long (maximum 100 characters)")
    58→	}
    59→
    60→	// Check for invalid characters
    61→	validIDPattern := regexp.MustCompile(`^[a-zA-Z0-9\-_@/.]+$`)
    62→	if !validIDPattern.MatchString(id) {
    63→		return fmt.Errorf("model ID contains invalid characters (allowed: letters, numbers, -, _, @, /, .)")
    64→	}
    65→
    66→	// Ensure it doesn't start or end with special characters
    67→	if strings.HasPrefix(id, "-") || strings.HasSuffix(id, "-") ||
    68→		strings.HasPrefix(id, "_") || strings.HasSuffix(id, "_") {
    69→		return fmt.Errorf("model ID cannot start or end with dash or underscore")
    70→	}
    71→
    72→	return nil
    73→}
