   176→// validateCapabilitiesForProvider ensures capabilities are valid for the provider
   177→func (v *LLMModelValidator) validateCapabilitiesForProvider(provider string, capabilities []string) error {
   178→	providerCapabilities := map[string][]string{
   179→		"openai": {
   180→			"code", "analysis", "planning", "reasoning", "multimodal", "function_calling",
   181→		},
   182→		"anthropic": {
   183→			"code", "analysis", "planning", "reasoning", "multimodal",
   184→		},
   185→		"azure": {
   186→			"code", "analysis", "planning", "reasoning", "multimodal", "function_calling",
   187→		},
   188→		"local": {
   189→			"code", "analysis", "planning", "reasoning",
   190→		},
   191→	}
   192→
   193→	validCaps, exists := providerCapabilities[provider]
   194→	if !exists {
   195→		// For unknown providers, allow all capabilities
   196→		return nil
   197→	}
   198→
   199→	for _, capability := range capabilities {
   200→		if !contains(validCaps, capability) {
   201→			return fmt.Errorf("capability '%s' not supported by provider '%s'", capability, provider)
   202→		}
   203→	}
   204→
   205→	return nil
   206→}
