   208→// validateTokenLimits validates token limits based on provider and known model limits
   209→func (v *LLMModelValidator) validateTokenLimits(maxTokens int, provider string) error {
   210→	// General limits
   211→	if maxTokens < 1000 {
   212→		return fmt.Errorf("max_tokens too low (minimum 1000)")
   213→	}
   214→
   215→	if maxTokens > 2000000 {
   216→		return fmt.Errorf("max_tokens too high (maximum 2000000)")
   217→	}
   218→
   219→	// Provider-specific limits
   220→	switch provider {
   221→	case "openai":
   222→		if maxTokens > 1000000 {
   223→			return fmt.Errorf("max_tokens for OpenAI models cannot exceed 1000000")
   224→		}
   225→	case "anthropic":
   226→		if maxTokens > 200000 {
   227→			return fmt.Errorf("max_tokens for Anthropic models cannot exceed 200000")
   228→		}
   229→	case "local":
   230→		// More lenient for local models
   231→		if maxTokens > 100000 {
   232→			return fmt.Errorf("max_tokens for local models should not exceed 100000 (consider memory constraints)")
   233→		}
   234→	}
   235→
   236→	return nil
   237→}
