   239→// ValidateModelUpdate validates changes when updating a model
   240→func (v *LLMModelValidator) ValidateModelUpdate(existing, updated *models.LLMModel) error {
   241→	if existing == nil {
   242→		return fmt.Errorf("existing model cannot be nil")
   243→	}
   244→	if updated == nil {
   245→		return fmt.Errorf("updated model cannot be nil")
   246→	}
   247→
   248→	// ID cannot be changed
   249→	if existing.ID != updated.ID {
   250→		return fmt.Errorf("model ID cannot be changed (existing: %s, updated: %s)", existing.ID, updated.ID)
   251→	}
   252→
   253→	// Provider cannot be changed
   254→	if existing.Provider != updated.Provider {
   255→		return fmt.Errorf("model provider cannot be changed (existing: %s, updated: %s)", existing.Provider, updated.Provider)
   256→	}
   257→
   258→	// Validate the updated model
   259→	return v.ValidateLLMModel(updated)
   260→}
